    25→// Covers determines whether or not the ownerRules cover the servantRules in terms of allowed actions.
    26→// It returns whether or not the ownerRules cover and a list of the rules that the ownerRules do not cover.
    27→func Covers(ownerRules, servantRules []rbacv1.PolicyRule) (bool, []rbacv1.PolicyRule) {
    28→	// 1.  Break every servantRule into individual rule tuples: group, verb, resource, resourceName
    29→	// 2.  Compare the mini-rules against each owner rule.  Because the breakdown is down to the most atomic level, we're guaranteed that each mini-servant rule will be either fully covered or not covered by a single owner rule
    30→	// 3.  Any left over mini-rules means that we are not covered and we have a nice list of them.
    31→	// TODO: it might be nice to collapse the list down into something more human readable
    32→
    33→	subrules := []rbacv1.PolicyRule{}
    34→	for _, servantRule := range servantRules {
    35→		subrules = append(subrules, BreakdownRule(servantRule)...)
    36→	}
    37→
    38→	uncoveredRules := []rbacv1.PolicyRule{}
    39→	for _, subrule := range subrules {
    40→		covered := false
    41→		for _, ownerRule := range ownerRules {
    42→			if ruleCovers(ownerRule, subrule) {
    43→				covered = true
    44→				break
    45→			}
    46→		}
    47→
    48→		if !covered {
    49→			uncoveredRules = append(uncoveredRules, subrule)
    50→		}
    51→	}
    52→
    53→	return (len(uncoveredRules) == 0), uncoveredRules
    54→}
    55→
    56→// BreadownRule takes a rule and builds an equivalent list of rules that each have at most one verb, one
    57→// resource, and one resource name
    58→func BreakdownRule(rule rbacv1.PolicyRule) []rbacv1.PolicyRule {
    59→	subrules := []rbacv1.PolicyRule{}
    60→	for _, group := range rule.APIGroups {
    61→		for _, resource := range rule.Resources {
    62→			for _, verb := range rule.Verbs {
    63→				if len(rule.ResourceNames) > 0 {
    64→					for _, resourceName := range rule.ResourceNames {
    65→						subrules = append(subrules, rbacv1.PolicyRule{APIGroups: []string{group}, Resources: []string{resource}, Verbs: []string{verb}, ResourceNames: []string{resourceName}})
    66→					}
    67→
    68→				} else {
    69→					subrules = append(subrules, rbacv1.PolicyRule{APIGroups: []string{group}, Resources: []string{resource}, Verbs: []string{verb}})
    70→				}
    71→
    72→			}
    73→		}
    74→	}
    75→
    76→	// Non-resource URLs are unique because they only combine with verbs.
    77→	for _, nonResourceURL := range rule.NonResourceURLs {
    78→		for _, verb := range rule.Verbs {
    79→			subrules = append(subrules, rbacv1.PolicyRule{NonResourceURLs: []string{nonResourceURL}, Verbs: []string{verb}})
    80→		}
    81→	}
    82→
    83→	return subrules
    84→}
